import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../utils/api';
import Sidebar from '../components/common/Sidebar';
import { useAuth } from '../context/AuthContext';

export default function OnboardingPage() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [activeSection, setActiveSection] = useState('quickstart');
  const [csvFile, setCsvFile] = useState(null);
  const [importing, setImporting] = useState(false);
  const [importResult, setImportResult] = useState(null);
  const [importError, setImportError] = useState('');

  const handleImport = async () => {
    if (!csvFile) return;
    setImporting(true); setImportError(''); setImportResult(null);
    try {
      const fd = new FormData();
      fd.append('csv', csvFile);
      const res = await api.post('/import/monday-csv', fd, {
        headers: { 'Content-Type': 'multipart/form-data' },
      });
      setImportResult(res.data);
    } catch (err) {
      setImportError(err.response?.data?.error || 'Import failed');
    } finally {
      setImporting(false);
    }
  };

  const handleTemplateDownload = async () => {
    try {
      const res = await api.get('/import/template', { responseType: 'blob' });
      const url  = URL.createObjectURL(new Blob([res.data], { type: 'text/csv' }));
      const link = document.createElement('a');
      link.href  = url;
      link.setAttribute('download', 'monday-import-template.csv');
      document.body.appendChild(link); link.click();
      document.body.removeChild(link); URL.revokeObjectURL(url);
    } catch (err) { alert('Download failed'); }
  };

  const ROLES = {
    requester:    { icon: '👤', color: '#534AB7', label: 'Requester',   steps: ['Go to /requests/new', 'Fill in Title, Description, Quantity, Due Date', 'Attach STL/STEP/PDF files', 'Click "Save & Submit"', 'Track status in My Requests', 'Confirm reception when part is ready'] },
    coordinator:  { icon: '🎯', color: '#BA7517', label: 'Coordinator', steps: ['Review submitted requests in /requests', 'Check completeness → run Feasibility Review tab', 'Approve + set due date + assign printer & material', 'Assign technician', 'Monitor workflow in Planning Board', 'Archive completed requests'] },
    technician:   { icon: '⚙️',  color: '#3B6D11', label: 'Technician',  steps: ['View assigned requests in /requests', 'Check reserved material in "Update Status → Planned"', 'Click "In Progress" when printing starts', 'Fill "Printed" status: qty printed, material used', 'Complete Quality Check tab', 'Move to Ready for Pickup'] },
    manager:      { icon: '📊', color: '#185FA5', label: 'Manager',     steps: ['View live KPIs in /dashboard', 'Check Performance dashboard for lead time & on-time rate', 'Review Management dashboard for trends', 'Export reports from /reports', 'Monitor material stock in /stock'] },
    administrator:{ icon: '🔧', color: '#A32D2D', label: 'Admin',       steps: ['Manage users in /admin → Users tab', 'Add printers in /admin → Printers tab', 'Add materials and set stock levels in /admin → Materials', 'Import Monday.com data in /onboarding → Import tab', 'Run stock recalculation in /stock if quantities drift'] },
  };

  const roleData = ROLES[user?.role] || ROLES.requester;

  const sections = [
    { key: 'quickstart', label: '🚀 Quick Start' },
    { key: 'workflow',   label: '🔄 Workflow' },
    { key: 'myrole',     label: `${roleData.icon} My Role` },
    ...(['administrator','coordinator'].includes(user?.role) ? [{ key: 'import', label: '📥 Import Monday.com' }] : []),
  ];

  return (
    <div className="page">
      <Sidebar />
      <div className="main-content">
        <div className="page-header">
          <div>
            <h1 style={{ fontSize: '1.3rem', fontFamily: 'var(--font-heading)' }}>
              Getting Started — 3D Print Manager
            </h1>
            <p style={{ color: 'var(--text-muted)', fontSize: '0.8rem', marginTop: '0.2rem' }}>
              Replaces Monday.com · {user?.firstName} {user?.lastName} · {user?.role}
            </p>
          </div>
        </div>

        <div className="page-body">
          {/* Tabs */}
          <div className="tabs" style={{ marginBottom: '1.5rem' }}>
            {sections.map(s => (
              <button key={s.key} className={`tab ${activeSection === s.key ? 'active' : ''}`}
                onClick={() => setActiveSection(s.key)}>
                {s.label}
              </button>
            ))}
          </div>

          {/* ── Quick Start ─────────────────────────────────────────────── */}
          {activeSection === 'quickstart' && (
            <div>
              {/* Welcome banner */}
              <div style={{ padding: '1.25rem 1.5rem', background: 'linear-gradient(135deg, var(--accent-dim), var(--blue-dim))', borderRadius: 12, marginBottom: '1.5rem', border: '1px solid var(--border-light)' }}>
                <div style={{ fontFamily: 'var(--font-heading)', fontSize: '1.1rem', fontWeight: 700, marginBottom: '0.5rem' }}>
                  Welcome to 3D Print Manager — Avocarbon
                </div>
                <p style={{ color: 'var(--text-secondary)', fontSize: '0.85rem', margin: 0, lineHeight: 1.6 }}>
                  This system replaces the Monday.com board for managing all 3D printing requests. It provides complete request lifecycle management, real-time dashboards, quality control, material stock tracking, and Excel exports.
                </p>
              </div>

              <div className="grid-2" style={{ gap: '1rem', marginBottom: '1.5rem' }}>
                {/* Key actions */}
                <div className="card">
                  <h3 style={{ fontSize: '0.85rem', fontWeight: 700, marginBottom: '1rem', color: 'var(--accent)' }}>
                    ⚡ Key Actions for You
                  </h3>
                  {roleData.steps.map((step, i) => (
                    <div key={i} style={{ display: 'flex', gap: '0.75rem', padding: '0.6rem 0', borderBottom: i < roleData.steps.length - 1 ? '1px solid var(--border)' : 'none' }}>
                      <div style={{ width: 22, height: 22, borderRadius: '50%', background: `${roleData.color}22`, color: roleData.color, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.72rem', fontWeight: 700, flexShrink: 0 }}>
                        {i + 1}
                      </div>
                      <span style={{ fontSize: '0.83rem', color: 'var(--text-primary)' }}>{step}</span>
                    </div>
                  ))}
                </div>

                {/* Navigation map */}
                <div className="card">
                  <h3 style={{ fontSize: '0.85rem', fontWeight: 700, marginBottom: '1rem', color: 'var(--blue)' }}>
                    🗺 Navigation Map
                  </h3>
                  {[
                    { path: '/requests',              icon: '📋', label: 'Requests', desc: 'All print requests' },
                    { path: '/requests/new',           icon: '➕', label: 'New Request', desc: 'Submit a new request' },
                    { path: '/planning',               icon: '📅', label: 'Planning Board', desc: 'Kanban workflow view' },
                    { path: '/dashboard',              icon: '📊', label: 'Dashboard', desc: 'Operational KPIs' },
                    { path: '/dashboard/performance',  icon: '📈', label: 'Performance', desc: 'Lead time, on-time rate' },
                    { path: '/stock',                  icon: '🧵', label: 'Material Stock', desc: 'Stock levels & history' },
                    { path: '/archive',                icon: '🗄', label: 'Archive', desc: 'Completed & archived' },
                    { path: '/reports',                icon: '⬇️', label: 'Reports', desc: 'Excel exports' },
                  ].filter(item => {
                    if (['/planning','/dashboard','/dashboard/performance','/stock','/archive','/reports'].includes(item.path) && user?.role === 'requester') return false;
                    return true;
                  }).map((item, i) => (
                    <div key={i} onClick={() => navigate(item.path)}
                      style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', padding: '0.5rem 0.6rem', borderRadius: 6, cursor: 'pointer', marginBottom: '0.25rem', transition: 'var(--transition)' }}
                      onMouseEnter={e => e.currentTarget.style.background = 'var(--bg-hover)'}
                      onMouseLeave={e => e.currentTarget.style.background = 'transparent'}>
                      <span style={{ fontSize: '1rem', width: 24, textAlign: 'center' }}>{item.icon}</span>
                      <div>
                        <div style={{ fontSize: '0.83rem', fontWeight: 600 }}>{item.label}</div>
                        <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)' }}>{item.desc}</div>
                      </div>
                      <span style={{ marginLeft: 'auto', color: 'var(--text-muted)', fontSize: '0.75rem' }}>→</span>
                    </div>
                  ))}
                </div>
              </div>

              {/* Accounts */}
              <div className="card">
                <h3 style={{ fontSize: '0.85rem', fontWeight: 700, marginBottom: '1rem' }}>🔑 Default Accounts (change passwords after first login)</h3>
                <div className="table-container">
                  <table>
                    <thead><tr><th>Email</th><th>Role</th><th>Can do</th></tr></thead>
                    <tbody>
                      {[
                        ['wael.charaabi@avocarbon.com',  'Coordinator',    'Validate, approve, plan, assign, archive'],
                        ['salah.benachour@avocarbon.com','Manager',        'View all dashboards and KPIs'],
                        ['technician@avocarbon.com',     'Technician',     'Execute prints, QC, record data'],
                        ['requester@avocarbon.com',      'Requester',      'Submit and track requests'],
                        ['admin@avocarbon.com',          'Administrator',  'Manage users, printers, materials'],
                      ].map(([email, role, can], i) => (
                        <tr key={i}>
                          <td style={{ fontFamily: 'var(--font-mono)', fontSize: '0.78rem' }}>{email}</td>
                          <td><span style={{ fontSize: '0.72rem', fontWeight: 600, padding: '0.15rem 0.5rem', borderRadius: 4, background: 'var(--blue-dim)', color: 'var(--blue)' }}>{role}</span></td>
                          <td style={{ fontSize: '0.78rem', color: 'var(--text-secondary)' }}>{can}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
                <div className="alert alert-warning" style={{ marginTop: '1rem', fontSize: '0.78rem' }}>
                  Default password for all accounts: <strong>Admin123!</strong> — Change immediately in production.
                </div>
              </div>
            </div>
          )}

          {/* ── Workflow ─────────────────────────────────────────────────── */}
          {activeSection === 'workflow' && (
            <div className="card">
              <h3 style={{ fontSize: '0.85rem', fontWeight: 700, marginBottom: '1.25rem' }}>Complete Request Lifecycle</h3>
              {[
                { status: 'Draft',                  role: 'Requester',   color: '#64748b', desc: 'Request saved but not yet submitted' },
                { status: 'Submitted',              role: 'Requester',   color: '#3b82f6', desc: 'Sent for review. Coordinator receives notification.' },
                { status: 'Completeness Check',     role: 'Coordinator', color: '#06b6d4', desc: 'Coordinator verifies all required fields and files are present' },
                { status: 'Feasibility Review',     role: 'Coordinator', color: '#8b5cf6', desc: 'Technical review: printable? machine? material? cost? duration?' },
                { status: 'Approved',               role: 'Coordinator', color: '#22c55e', desc: 'Approved with due date. Cannot skip feasibility.' },
                { status: 'Prioritized → Planned',  role: 'Coordinator', color: '#f97316', desc: 'Printer assigned, material reserved, dates set' },
                { status: 'Assigned',               role: 'Coordinator', color: '#a855f7', desc: 'Technician assigned and notified' },
                { status: 'In Progress',            role: 'Technician',  color: '#3b82f6', desc: 'Printing started' },
                { status: 'Printed',                role: 'Technician',  color: '#10b981', desc: 'Printing done. Record actual material used.' },
                { status: 'Quality Check',          role: 'Technician',  color: '#f59e0b', desc: 'Dimensional, surface, functional, visual checks. Cannot skip.' },
                { status: 'Ready for Pickup',       role: 'Technician',  color: '#22c55e', desc: 'Part ready. Requester receives notification.' },
                { status: 'Awaiting Confirmation',  role: 'Requester',   color: '#06b6d4', desc: 'Requester confirms receipt' },
                { status: 'Completed',              role: 'Requester',   color: '#22c55e', desc: 'Request closed. Requester has confirmed.' },
                { status: 'Archived',               role: 'Coordinator', color: '#475569', desc: 'Historical record. Counted in all KPIs.' },
              ].map((s, i) => (
                <div key={i} style={{ display: 'flex', gap: '1rem', alignItems: 'flex-start', marginBottom: '0.75rem' }}>
                  <div style={{ width: 10, height: 10, borderRadius: '50%', background: s.color, flexShrink: 0, marginTop: '0.35rem' }}/>
                  <div style={{ flex: 1 }}>
                    <div style={{ display: 'flex', gap: '0.75rem', alignItems: 'center', flexWrap: 'wrap' }}>
                      <span style={{ fontWeight: 600, fontSize: '0.85rem', color: s.color }}>{s.status}</span>
                      <span style={{ fontSize: '0.72rem', padding: '0.1rem 0.5rem', borderRadius: 4, background: 'var(--bg-hover)', color: 'var(--text-muted)' }}>{s.role}</span>
                    </div>
                    <p style={{ margin: '0.2rem 0 0', fontSize: '0.78rem', color: 'var(--text-secondary)' }}>{s.desc}</p>
                  </div>
                  {i < 13 && <div style={{ color: 'var(--text-muted)', fontSize: '0.8rem', flexShrink: 0 }}>↓</div>}
                </div>
              ))}
              <div className="alert alert-info" style={{ marginTop: '1rem', fontSize: '0.78rem' }}>
                Alternative paths: <strong>Rejected</strong>, <strong>Blocked</strong>, <strong>On Hold</strong>, <strong>Rework Required</strong>, <strong>Cancelled</strong>, <strong>Waiting for Material/Machine</strong>
              </div>
            </div>
          )}

          {/* ── My Role ──────────────────────────────────────────────────── */}
          {activeSection === 'myrole' && (
            <div className="card">
              <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '1.5rem' }}>
                <span style={{ fontSize: '2rem' }}>{roleData.icon}</span>
                <div>
                  <div style={{ fontFamily: 'var(--font-heading)', fontSize: '1.1rem', fontWeight: 800 }}>
                    Your role: {roleData.label}
                  </div>
                  <div style={{ color: 'var(--text-muted)', fontSize: '0.8rem' }}>
                    {user?.firstName} {user?.lastName} · {user?.department}
                  </div>
                </div>
              </div>
              {roleData.steps.map((step, i) => (
                <div key={i} style={{ display: 'flex', gap: '0.75rem', padding: '0.85rem 0', borderBottom: '1px solid var(--border)' }}>
                  <div style={{ width: 28, height: 28, borderRadius: '50%', background: `${roleData.color}22`, color: roleData.color, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.85rem', fontWeight: 700, flexShrink: 0 }}>
                    {i + 1}
                  </div>
                  <span style={{ fontSize: '0.85rem', color: 'var(--text-primary)', paddingTop: '0.25rem' }}>{step}</span>
                </div>
              ))}
              <div style={{ marginTop: '1.5rem', display: 'flex', gap: '0.75rem' }}>
                {user?.role !== 'requester' && (
                  <button className="btn btn-primary" onClick={() => navigate('/dashboard')}>
                    Go to Dashboard →
                  </button>
                )}
                <button className="btn btn-secondary" onClick={() => navigate('/requests')}>
                  View Requests →
                </button>
              </div>
            </div>
          )}

          {/* ── Import Monday.com ────────────────────────────────────────── */}
          {activeSection === 'import' && ['administrator','coordinator'].includes(user?.role) && (
            <div>
              <div className="grid-2" style={{ gap: '1rem' }}>
                <div className="card">
                  <h3 style={{ fontSize: '0.85rem', fontWeight: 700, marginBottom: '1rem' }}>
                    📥 Import from Monday.com CSV
                  </h3>
                  <p style={{ fontSize: '0.82rem', color: 'var(--text-secondary)', marginBottom: '1rem', lineHeight: 1.6 }}>
                    Export your Monday.com board as CSV and import it here. Historical requests will be imported as <strong>Archived</strong> — they appear in all KPIs and reports but don't interfere with the active workflow.
                  </p>

                  <div style={{ marginBottom: '1rem' }}>
                    <button className="btn btn-ghost btn-sm" onClick={handleTemplateDownload}>
                      ↓ Download CSV Template
                    </button>
                    <p style={{ fontSize: '0.72rem', color: 'var(--text-muted)', marginTop: '0.35rem' }}>
                      Use this template to format your Monday.com export correctly.
                    </p>
                  </div>

                  <div className="form-group" style={{ marginBottom: '1rem' }}>
                    <label className="form-label">Select CSV File</label>
                    <input
                      type="file" accept=".csv"
                      onChange={e => { setCsvFile(e.target.files[0]); setImportResult(null); setImportError(''); }}
                      style={{ display: 'none' }} id="csv-input"
                    />
                    <label htmlFor="csv-input" className="btn btn-secondary" style={{ cursor: 'pointer', display: 'inline-flex' }}>
                      📎 Choose CSV file
                    </label>
                    {csvFile && (
                      <span style={{ marginLeft: '0.75rem', fontSize: '0.82rem', color: 'var(--text-secondary)' }}>
                        {csvFile.name} ({(csvFile.size / 1024).toFixed(1)} KB)
                      </span>
                    )}
                  </div>

                  <button
                    className="btn btn-primary"
                    onClick={handleImport}
                    disabled={!csvFile || importing}
                  >
                    {importing ? <><span className="spinner" style={{ width: 14, height: 14 }}/> Importing…</> : '📥 Import'}
                  </button>

                  {importError && (
                    <div className="alert alert-error" style={{ marginTop: '1rem' }}>{importError}</div>
                  )}
                  {importResult && (
                    <div className="alert alert-success" style={{ marginTop: '1rem' }}>
                      <strong>✅ Import complete</strong>
                      <div style={{ marginTop: '0.35rem', fontSize: '0.82rem' }}>
                        Imported: <strong>{importResult.imported}</strong> requests · Skipped: {importResult.skipped}
                      </div>
                      {importResult.errors?.length > 0 && (
                        <div style={{ marginTop: '0.35rem', fontSize: '0.75rem', color: 'var(--yellow)' }}>
                          {importResult.errors.map((e, i) => <div key={i}>{e}</div>)}
                        </div>
                      )}
                      <div style={{ marginTop: '0.35rem', fontSize: '0.75rem', color: 'var(--text-muted)' }}>
                        {importResult.note}
                      </div>
                    </div>
                  )}
                </div>

                <div className="card">
                  <h3 style={{ fontSize: '0.85rem', fontWeight: 700, marginBottom: '1rem' }}>
                    📋 Expected CSV Columns
                  </h3>
                  {[
                    ['Title *',       'Request name/item name (required)'],
                    ['Status',        'Done, In Progress, Pending, Cancelled…'],
                    ['Priority',      'Critical, High, Normal, Low'],
                    ['Requester',     'Name of the person who made the request'],
                    ['Department',    'Team or department'],
                    ['Due Date',      'YYYY-MM-DD format recommended'],
                    ['Description',   'Notes or purpose'],
                    ['Quantity',      'Number of pieces'],
                    ['Material',      'Filament type'],
                  ].map(([col, desc], i) => (
                    <div key={i} style={{ display: 'flex', gap: '1rem', padding: '0.45rem 0', borderBottom: '1px solid var(--border)', fontSize: '0.82rem' }}>
                      <span style={{ fontFamily: 'var(--font-mono)', fontSize: '0.78rem', color: 'var(--accent)', minWidth: 120 }}>{col}</span>
                      <span style={{ color: 'var(--text-secondary)' }}>{desc}</span>
                    </div>
                  ))}
                  <div className="alert alert-info" style={{ marginTop: '1rem', fontSize: '0.75rem' }}>
                    Column names are flexible — the importer recognizes common variants. Only "Title" is required.
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
